1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const FLOAT_ROUNDING_TOLERANCE = 1e-9;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Array<Item> };
14	type Scenario = {
15	  customer: { yearsWithMHPCO: number };
16	  steps: Array<QuoteStep>;
17	};
18	
19	const roundUpInMHPCOFavor = (amount: number): number =>
20	  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);
21	
22	const basePremiumFor = (items: Array<Item>): number =>
23	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
24	
25	const quoteStep = (step: QuoteStep): { premium: number } => {
26	  const basePremium = basePremiumFor(step.items);
27	  const premiumBeforeRounding =
28	    basePremium * (1 + FIRST_INSURANCE_SURCHARGE) + PROCESSING_FEE;
29	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
30	};
31	
32	export const processScenario = (scenario: unknown): unknown => {
33	  const { steps } = scenario as Scenario;
34	  return { results: steps.map(quoteStep) };
35	};
